//-------------------------------------------------------------------------
// 운임추가, 월대추가 버튼 클릭 시 해당 영역 visible 처리
//-------------------------------------------------------------------------
scwin.reWindLayer = function (str) {
  //apDiv10 : 구간단가 추가영역
  //apDiv11 : 월대금액 추가영역
  $c.data.undoAll($p, ds_PosFare);
  $c.data.undoAll($p, ds_FixCost);
  if (str == '10') {
    if (grp_tabs4_sub.getStyle("display") == 'none') {
      grp_main.setSize(null, 250);
      grp_tabs4_sub.show();
      grp_tabs7_sub.hide();
    } else {
      grp_tabs4_sub.hide();
      grp_tabs7_sub.hide();
      grp_main.setSize(null, null);
    }
  } else if (str == '11') {
    if (grp_tabs7_sub.getStyle("display") == 'none') {
      grp_main.setSize(null, 250);
      grp_tabs4_sub.hide();
      grp_tabs7_sub.show();
    } else {
      grp_tabs4_sub.hide();
      grp_tabs7_sub.hide();
      grp_main.setSize(null, null);
    }
  } else if (str == 'off') {
    grp_tabs4_sub.hide();
    grp_tabs7_sub.hide();
    grp_main.setSize(null, null);
  }
};

