//-------------------------------------------------------------------------
scwin.sbm_SaveClntMaster_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) return;
  await $c.win.alert($p, "성공적으로 저장되었습니다.");
  scwin.RetriveOfClient();
};

//-------------------------------------------------------------------------
// 삭제 submitdone
//-------------------------------------------------------------------------
scwin.sbm_delete_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) return;
  var str = ds_Result.getCellData(0, "outMsg");

  //if (!isUndefined(str)) {
  if (ds_Result.getRowCount() > 0 && !$c.util.isEmpty($p, ds_Result.getCellData(0, "outMsg"))) {
    $c.win.alert($p, str);
  }

  // 재조회
  scwin.RetriveOfClient();
};

